using CertDesk.Models; using CertDesk.Services;
namespace CertDesk.Forms;
public sealed class MchdView:UserControl
{ readonly User user; readonly MchdService service; readonly DataGridView grid=Ui.Grid(); readonly TextBox search=Ui.TextBox(); readonly ComboBox status=Ui.Combo(), reg=Ui.Combo();
 public MchdView(User user){this.user=user; service=new(user); var top=new FlowLayoutPanel{Dock=DockStyle.Top,Height=88}; status.Items.AddRange(["Все","active","warning","expired","revoked","archived"]); status.SelectedIndex=0; reg.Items.AddRange(["Все","Зарегистрирована","Не зарегистрирована"]); reg.SelectedIndex=0; var add=Ui.Button("Добавить"); var edit=Ui.Button("Изменить"); var revoke=Ui.Button("Отозвать"); var arch=Ui.Button("Архивировать"); var refresh=Ui.Button("Обновить"); var export=Ui.Button("Экспорт"); top.Controls.AddRange([Ui.Label("Поиск"),search,Ui.Label("Статус"),status,Ui.Label("Регистрация"),reg,add,edit,revoke,arch,refresh,export]); Controls.Add(grid); Controls.Add(top); search.TextChanged+=(_,_)=>LoadData(); status.SelectedIndexChanged+=(_,_)=>LoadData(); reg.SelectedIndexChanged+=(_,_)=>LoadData(); refresh.Click+=(_,_)=>LoadData(); add.Click+=(_,_)=>Open(0); edit.Click+=(_,_)=>Open(Id()); revoke.Click+=(_,_)=>Set("revoked","отзыв МЧД"); arch.Click+=(_,_)=>Set("archived","архивирование МЧД"); export.Click+=(_,_)=>MessageBox.Show("Используйте раздел Отчеты для CSV/XLSX экспорта."); if(!AuthService.CanEdit(user)){add.Visible=edit.Visible=revoke.Visible=arch.Visible=false;} LoadData();}
 int Id()=>grid.CurrentRow==null?0:Convert.ToInt32(grid.CurrentRow.Cells["id"].Value); bool EnsureEdit(){if(!AuthService.CanEdit(user)){MessageBox.Show("Недостаточно прав для выполнения операции");return false;} return true;} void Open(int id){if(!EnsureEdit())return; using var f=new MchdEditForm(service.Get(id)??new Mchd{ValidFrom=DateTime.Today,ValidTo=DateTime.Today.AddYears(1)},service); if(f.ShowDialog()==DialogResult.OK)LoadData();} void Set(string s,string a){if(!EnsureEdit()||Id()==0)return; service.SetStatus(Id(),s,a);LoadData();} void LoadData(){grid.DataSource=service.Search(search.Text,status.Text,reg.Text); if(grid.Columns.Contains("id"))grid.Columns["id"].Visible=false;}
}
